__asm__(
".section .text\n"
".globl _start\n"
"_start:\n"
"  la t0, supervisor_trap\n"
"  csrw stvec, t0\n"
"  li t0, (1 << 8)\n"
"  csrw medeleg, t0\n"
"  la t0, user_entry\n"
"  csrw mepc, t0\n"
"  csrr t0, mstatus\n"
"  li t1, ~(3 << 11)\n"
"  and t0, t0, t1\n"
"  csrw mstatus, t0\n"
"  mret\n"
"  li a0, 1\n"
"  ebreak\n"
"user_entry:\n"
"  ecall\n"
"  li t0, 0x10000000\n"
"  li t1, 'S'\n"
"  sb t1, 0(t0)\n"
"  li a0, 0\n"
"  ebreak\n"
"supervisor_trap:\n"
"  csrr t0, scause\n"
"  li t1, 8\n"
"  bne t0, t1, trap_fail\n"
"  csrr t0, sepc\n"
"  addi t0, t0, 4\n"
"  csrw sepc, t0\n"
"  sret\n"
"trap_fail:\n"
"  li a0, 2\n"
"  ebreak\n"
);
